voidConfigDialog::validate(QTableWidgetItem*item){
boolstatus=true;

if(item==nullptr){
for(inti=0;i<ui->profileTable->rowCount();i++){
for(intj=0;j<ui->profileTable->columnCount();j++){
QTableWidgetItem*_item=ui->profileTable->item(i,j);

if(_item->text().isEmpty()&&j!=2){
_item->setBackground(Qt::red);
_item->setToolTip(tr("Thisfieldisrequired"));
status=false;
break;
}else{
_item->setBackground(QBrush());
_item->setToolTip(QString());
}
}

if(!status){
break;
}
}
}else{
if(item->text().isEmpty()&&item->column()!=2){
item->setBackground(Qt::red);
item->setToolTip(tr("Thisfieldisrequired"));
status=false;
}else{
item->setBackground(QBrush());
item->setToolTip(QString());
}
}

ui->buttonBox->button(QDialogButtonBox::Ok)->setEnabled(status);
}

