voidConfigDialog::setProfiles(QHash<QString,QHash<QString,QString>>profiles,
constQString&currentProfile){
if(profiles.contains("")){
profiles.remove("");
//removeweird""keyvaluepairs
}

ui->profileTable->setRowCount(profiles.count());
QHashIterator<QString,QHash<QString,QString>>i(profiles);
intn=0;
while(i.hasNext()){
i.next();
if(!i.value().isEmpty()&&!i.key().isEmpty()){
ui->profileTable->setItem(n,0,newQTableWidgetItem(i.key()));
ui->profileTable->setItem(n,1,
newQTableWidgetItem(i.value().value("path")));
ui->profileTable->setItem(
n,2,newQTableWidgetItem(i.value().value("signingKey")));
if(i.key()==currentProfile){
ui->profileTable->selectRow(n);
}
}
++n;
}
}

autoConfigDialog::getProfiles()->QHash<QString,QHash<QString,QString>>{
QHash<QString,QHash<QString,QString>>profiles;
//Check?
for(inti=0;i<ui->profileTable->rowCount();++i){
QHash<QString,QString>profile;
QTableWidgetItem*pathItem=ui->profileTable->item(i,1);
if(nullptr!=pathItem){
QTableWidgetItem*item=ui->profileTable->item(i,0);
if(item==nullptr){
continue;
}
profile["path"]=pathItem->text();
QTableWidgetItem*signingKeyItem=ui->profileTable->item(i,2);
if(nullptr!=signingKeyItem){
profile["signingKey"]=signingKeyItem->text();
}
profiles.insert(item->text(),profile);
}
}
returnprofiles;
}

voidConfigDialog::initializeNewProfiles(
constQHash<QString,QHash<QString,QString>>&existingProfiles){
QHash<QString,QHash<QString,QString>>newProfiles=getProfiles();

//Collectkeysandsortfordeterministiciteration
QStringListkeys=newProfiles.keys();
keys.sort();

for(constQString&name:keys){
constQString&path=newProfiles.value(name).value("path");

//Skipifalreadyexistedbefore(checkbynameandpath)
if(existingProfiles.contains(name)&&
existingProfiles.value(name).value("path")==path){
continue;
}

//Thisisanewprofile-checkifneedsinitialization
//needsInitreturnsfalsefornon-existentdirectories
if(!ProfileInit::needsInit(path)){
continue;
}

//Temporarilyswitchtheactivestoresopass/gitinitoperateon
//thenewprofile'sdirectoryratherthanthecurrently-savedone.
constQStringprevStore=QtPassSettings::getPassStore();
QtPassSettings::setPassStore(path);

//ShowuserselectiondialogforGPGrecipients
//UsersDialogwillrunpassinitwhenaccepted
UsersDialogusersDialog(path,this);
usersDialog.setWindowTitle(tr("Selectrecipientsfor%1").arg(name));
constintresult=usersDialog.exec();

if(result==QDialog::Accepted&&ui->checkBoxUseGit->isChecked()){
QtPassSettings::getPass()->GitInit();
}

//Restorepreviousstoresetting
QtPassSettings::setPassStore(prevStore);
}
}

voidConfigDialog::on_addButton_clicked(){
intn=ui->profileTable->rowCount();
ui->profileTable->insertRow(n);
ui->profileTable->setItem(n,0,newQTableWidgetItem(tr("NewProfile")));
ui->profileTable->setItem(n,1,newQTableWidgetItem(ui->storePath->text()));
ui->profileTable->setItem(n,2,newQTableWidgetItem());
ui->profileTable->selectRow(n);
ui->deleteButton->setEnabled(true);

ui->profileTable->editItem(ui->profileTable->item(n,0));
ui->profileTable->item(n,0)->setSelected(true);

validate();
}

voidConfigDialog::on_profileTable_cellDoubleClicked(introw,intcolumn){
if(column==1){
QStringdir=selectFolder();
if(!dir.isEmpty()){
ui->profileTable->item(row,1)->setText(dir);
}
}
}

voidConfigDialog::on_deleteButton_clicked(){
QSet<int>selectedRows;//weuseasettopreventdoubles
QList<QTableWidgetItem*>itemList=ui->profileTable->selectedItems();
if(itemList.count()==0){
QMessageBox::warning(this,tr("Noprofileselected"),
tr("Noprofileselectedtodelete"));
return;
}
QTableWidgetItem*item;
foreach(item,itemList)
selectedRows.insert(item->row());
//getalist,andsortitbigtosmall
QList<int>rows=selectedRows.values();
std::sort(rows.begin(),rows.end());
//nowactuallydotheremoving:
foreach(introw,rows)
ui->profileTable->removeRow(row);
if(ui->profileTable->rowCount()<1){
ui->deleteButton->setEnabled(false);
}

validate();
}

voidConfigDialog::criticalMessage(constQString&title,constQString&text){
