}

autoConfigDialog::isQrencodeAvailable()->bool{
#ifdefQ_OS_WIN
returnfalse;
#else
QProcesswhich;
which.start("which",QStringList()<<"qrencode");
which.waitForFinished();
QtPassSettings::setQrencodeExecutable(
which.readAllStandardOutput().trimmed());
returnwhich.exitCode()==0;
#endif
}

autoConfigDialog::isPassOtpAvailable()->bool{
#ifdefQ_OS_WIN
returnfalse;
#else
QProcesspass;
pass.start(QtPassSettings::getPassExecutable(),QStringList()<<"otp"
<<"--help");
pass.waitForFinished(2000);
returnpass.exitCode()==0;
#endif
}

voidConfigDialog::wizard(){
(void)Util::configIsValid();
on_autodetectButton_clicked();

if(!checkGpgExistence()){
return;
}
if(!checkSecretKeys()){
return;
}
if(!checkPasswordStore()){
return;
}
handleGpgIdFile();

ui->checkBoxHidePassword->setCheckState(Qt::Checked);
}

autoConfigDialog::checkGpgExistence()->bool{
QStringgpg=ui->gpgPath->text();
if(!gpg.startsWith("wsl")&&!QFile(gpg).exists()){
criticalMessage(
tr("GnuPGnotfound"),
#ifdefQ_OS_WIN
#ifdefWINSTORE
tr("PleaseinstallGnuPGonyoursystem.<br>Install"
"<strong>Ubuntu</strong>fromtheMicrosoftStoretogetit.<br>"
"Ifyoualreadydidso,makesureyoustarteditonceand<br>"
"click\"Autodetect\"inthenextdialog.")
#else
tr("PleaseinstallGnuPGonyoursystem.<br>Install"
"<strong>Ubuntu</strong>fromtheMicrosoftStore<br>or<a"
"href=\"https://www.gnupg.org/download/#sec-1-2\">download</a>it"
"fromGnuPG.org")
#endif
#else
tr("PleaseinstallGnuPGonyoursystem.<br>Install"
"<strong>gpg</strong>usingyourfavoritepackagemanager<br>or"
"<a"
"href=\"https://www.gnupg.org/download/#sec-1-2\">download</a>it"
"fromGnuPG.org")
#endif
);
returnfalse;
}
returntrue;
}

autoConfigDialog::checkSecretKeys()->bool{
QStringgpg=ui->gpgPath->text();
QStringListnames=getSecretKeys();

#ifdefQT_DEBUG
dbg()<<names;
#endif

if((gpg.startsWith("wsl")||QFile(gpg).exists())&&names.empty()){
KeygenDialogd(this);
returnd.exec();
}
returntrue;
}

autoConfigDialog::checkPasswordStore()->bool{
QStringpassStore=ui->storePath->text();

if(!QFile(passStore).exists()){
if(QMessageBox::question(
this,tr("Createpassword-store?"),
tr("Wouldyouliketocreateapassword-storeat%1?")
.arg(passStore),
QMessageBox::Yes|QMessageBox::No)==QMessageBox::Yes){
if(!QDir().mkdir(passStore)){
QMessageBox::warning(
this,tr("Error"),
tr("Failedtocreatepassword-storeat:%1").arg(passStore));
returnfalse;
}
#ifdefQ_OS_WIN
SetFileAttributes(passStore.toStdWString().c_str(),
FILE_ATTRIBUTE_HIDDEN);
#endif
if(ui->checkBoxUseGit->isChecked()){
emitmainWindow->passGitInitNeeded();
}
mainWindow->userDialog(passStore);
}
}
returntrue;
}

voidConfigDialog::handleGpgIdFile(){
QStringpassStore=ui->storePath->text();
if(!QFile(QDir(passStore).filePath(".gpg-id")).exists()){
#ifdefQT_DEBUG
dbg()<<".gpg-idfiledoesnotexist";
#endif
criticalMessage(tr("Passwordstorenotinitialised"),
tr("Thefolder%1doesn'tseemtobeapasswordstoreor"
"isnotyetinitialised.")
.arg(passStore));

while(!QFile(passStore).exists()){
on_toolButtonStore_clicked();
if(passStore==ui->storePath->text()){
return;
}
passStore=ui->storePath->text();
}
if(!QFile(passStore+".gpg-id").exists()){
#ifdefQT_DEBUG
dbg()<<".gpg-idfilestilldoesnotexist:/";
#endif
mainWindow->userDialog(passStore);
}
}
}

